    CONFIG: 'CONFIG',
    WORKFLOW_EVENT: 'WORKFLOW_EVENT',
    CUSTOM: 'CUSTOM',
    CLOSE: 'CLOSE',
    SET_AUTH: 'SET_AUTH',
    SET_CONFIG: 'SET_CONFIG',
